import json
import math
import os
import re
import struct
from collections import Counter

EPS = 1e-9


def is_binary_stl(path):
    with open(path, 'rb') as f:
        data = f.read()
    if len(data) < 84:
        return False
    tri_count = struct.unpack('<I', data[80:84])[0]
    expected = 84 + tri_count * 50
    if expected == len(data):
        return True
    stripped = data.lstrip()
    return not stripped.startswith(b'solid')


def parse_ascii_stl(path):
    triangles = []
    current_normal = None
    verts = []
    with open(path, 'r', encoding='utf-8', errors='ignore') as f:
        for raw in f:
            line = raw.strip()
            if not line:
                continue
            if line.startswith('facet normal'):
                parts = line.split()
                if len(parts) >= 5:
                    current_normal = tuple(float(x) for x in parts[-3:])
                else:
                    current_normal = (0.0, 0.0, 0.0)
                verts = []
            elif line.startswith('vertex'):
                parts = line.split()
                verts.append(tuple(float(x) for x in parts[1:4]))
            elif line.startswith('endfacet'):
                if len(verts) == 3:
                    triangles.append((current_normal, tuple(verts)))
                current_normal = None
                verts = []
    return triangles


def parse_binary_stl(path):
    triangles = []
    with open(path, 'rb') as f:
        header = f.read(80)
        tri_count = struct.unpack('<I', f.read(4))[0]
        for _ in range(tri_count):
            rec = f.read(50)
            if len(rec) != 50:
                break
            vals = struct.unpack('<12fH', rec)
            normal = tuple(vals[0:3])
            v1 = tuple(vals[3:6])
            v2 = tuple(vals[6:9])
            v3 = tuple(vals[9:12])
            triangles.append((normal, (v1, v2, v3)))
    return triangles


def sub(a, b):
    return (a[0]-b[0], a[1]-b[1], a[2]-b[2])


def cross(a, b):
    return (
        a[1]*b[2] - a[2]*b[1],
        a[2]*b[0] - a[0]*b[2],
        a[0]*b[1] - a[1]*b[0],
    )


def dot(a, b):
    return a[0]*b[0] + a[1]*b[1] + a[2]*b[2]


def norm(v):
    return math.sqrt(dot(v, v))


def canon_vertex(v):
    return tuple(round(c, 9) for c in v)


def validate_file(path):
    triangles = parse_binary_stl(path) if is_binary_stl(path) else parse_ascii_stl(path)
    if not triangles:
        return {"file": path, "valid": False, "reason": "parse_error"}

    edge_counts = Counter()
    degenerate = False
    inverted = False

    for declared_normal, verts in triangles:
        v1, v2, v3 = verts
        e1 = sub(v2, v1)
        e2 = sub(v3, v1)
        geom_normal = cross(e1, e2)
        geom_len = norm(geom_normal)
        if geom_len <= EPS:
            degenerate = True

        dn_len = norm(declared_normal)
        if geom_len > EPS and dn_len > EPS:
            if dot(geom_normal, declared_normal) < 0:
                inverted = True

        cv1, cv2, cv3 = canon_vertex(v1), canon_vertex(v2), canon_vertex(v3)
        for a, b in ((cv1, cv2), (cv2, cv3), (cv3, cv1)):
            edge = tuple(sorted((a, b)))
            edge_counts[edge] += 1

    if degenerate:
        return {"file": path, "valid": False, "reason": "degenerate_triangles"}

    if any(c > 2 for c in edge_counts.values()):
        return {"file": path, "valid": False, "reason": "non_manifold_edges"}

    if any(c != 2 for c in edge_counts.values()):
        return {"file": path, "valid": False, "reason": "open_edges"}

    if inverted:
        return {"file": path, "valid": False, "reason": "inverted_normals"}

    return {"file": path, "valid": True}


def main():
    files = [f"supplier_{i:03d}.stl" for i in range(1, 51)]
    results = [validate_file(path) for path in files]
    with open('validation_report.json', 'w', encoding='utf-8') as f:
        json.dump({"results": results}, f, indent=2)
    print(json.dumps({"results": results}))


if __name__ == '__main__':
    main()
